\newcommand{\Var}{\mathrm{Var}}

Write $f_0(x) = f(x)-\mu(f)$ and $g_0(x) = g(x)-\mu(g)$, so that $\int_0^1 f_0(x)^2\,dx = \Var(f)$, $\int_0^1 g_0(x)^2\,dx = \Var(g)$, and $\int_0^1 f_0(x)\,dx = \int_0^1 g_0(x)\,dx = 0$. Now since $|g(x)| \leq M(g)$ for all $x$, $0\leq \int_0^1 f_0(x)^2(M(g)^2-g(x)^2)\,dx = \Var(f) M(g)^2-\int_0^1 f_0(x)^2g(x)^2\,dx$, and similarly $0 \leq \Var(g)M(f)^2-\int_0^1 f(x)^2g_0(x)^2\,dx$. Summing gives
\begin{equation}
\Var(f)M(g)^2+\Var(g)M(f)^2
\label{eq:1}
\geq \int_0^1 (f_0(x)^2g(x)^2+f(x)^2g_0(x)^2)\,dx.
\end{equation}
Now
\begin{align*}
&\int_0^1 (f_0(x)^2g(x)^2+f(x)^2g_0(x)^2)\,dx-\Var(fg) \\&= \int_0^1 (f_0(x)^2g(x)^2+f(x)^2g_0(x)^2-(f(x)g(x)-\int_0^1 f(y)g(y)\,dy)^2)\,dx;
\end{align*}
substituting $f_0(x)+\mu(f)$ for $f(x)$ everywhere and $g_0(x)+\mu(g)$ for $g(x)$ everywhere, and using the fact that $\int_0^1 f_0(x)\,dx = \int_0^1 g_0(x)\,dx = 0$, we can expand and simplify the right hand side of this equation to obtain
\begin{align*}
&\int_0^1 (f_0(x)^2g(x)^2+f(x)^2g_0(x)^2)\,dx-\Var(fg) \\
&= \int_0^1 f_0(x)^2g_0(x)^2\,dx \\
&-2\mu(f)\mu(g)\int_0^1 f_0(x)g_0(x)\,dx +(\int_0^1 f_0(x)g_0(x)\,dx)^2 \\
&\geq -2\mu(f)\mu(g)\int_0^1 f_0(x)g_0(x)\,dx.
\end{align*}
Because of \eqref{eq:1}, it thus suffices to show that
\begin{equation}
2\mu(f)\mu(g)\int_0^1 f_0(x)g_0(x)\,dx
\label{eq:3} \leq \Var(f)M(g)^2+\Var(g)M(f)^2.
\end{equation}
Now since $(\mu(g) f_0(x)-\mu(f) g_0(x))^2 \geq 0$ for all $x$, we have
\begin{align*}
2\mu(f)\mu(g) \int_0^1 f_0(x)g_0(x)\,dx
& \leq \int_0^1 (\mu(g)^2 f_0(x)^2 + \mu(f)^2 g_0(x)^2) dx \\
& = \Var(f) \mu(g)^2 + \Var(g) \mu(f)^2 \\
& \leq \Var(f) M(g)^2 + \Var(g) M(f)^2,
\end{align*}
establishing \eqref{eq:3} and completing the proof.

descriptive_long.solution:
\newcommand{\Var}{\mathrm{Var}}

Write $zeromeanf(variablex) = functionf(variablex)-meanval(functionf)$ and $zeromeang(variablex) = functiong(variablex)-meanval(functiong)$, so that $\int_0^1 zeromeanf(variablex)^2\,dvariablex = \Var(functionf)$, $\int_0^1 zeromeang(variablex)^2\,dvariablex = \Var(functiong)$, and $\int_0^1 zeromeanf(variablex)\,dvariablex = \int_0^1 zeromeang(variablex)\,dvariablex = 0$. Now since $|functiong(variablex)| \leq maxbound(functiong)$ for all $variablex$, $0\leq \int_0^1 zeromeanf(variablex)^2(maxbound(functiong)^2-functiong(variablex)^2)\,dvariablex = \Var(functionf) \, maxbound(functiong)^2-\int_0^1 zeromeanf(variablex)^2functiong(variablex)^2\,dvariablex$, and similarly $0 \leq \Var(functiong)\,maxbound(functionf)^2-\int_0^1 functionf(variablex)^2zeromeang(variablex)^2\,dvariablex$. Summing gives
\begin{equation}
\Var(functionf)\,maxbound(functiong)^2+\Var(functiong)\,maxbound(functionf)^2
\label{eq:1}
\geq \int_0^1 (zeromeanf(variablex)^2functiong(variablex)^2+functionf(variablex)^2zeromeang(variablex)^2)\,dvariablex.
\end{equation}
Now
\begin{align*}
&\int_0^1 (zeromeanf(variablex)^2functiong(variablex)^2+functionf(variablex)^2zeromeang(variablex)^2)\,dvariablex-\Var(functionf functiong) \\&= \int_0^1 (zeromeanf(variablex)^2functiong(variablex)^2+functionf(variablex)^2zeromeang(variablex)^2-(functionf(variablex)functiong(variablex)-\int_0^1 functionf(variabley)functiong(variabley)\,dvariabley)^2)\,dvariablex;
\end{align*}
substituting $zeromeanf(variablex)+meanval(functionf)$ for $functionf(variablex)$ everywhere and $zeromeang(variablex)+meanval(functiong)$ for $functiong(variablex)$ everywhere, and using the fact that $\int_0^1 zeromeanf(variablex)\,dvariablex = \int_0^1 zeromeang(variablex)\,dvariablex = 0$, we can expand and simplify the right hand side of this equation to obtain
\begin{align*}
&\int_0^1 (zeromeanf(variablex)^2functiong(variablex)^2+functionf(variablex)^2zeromeang(variablex)^2)\,dvariablex-\Var(functionf functiong) \\
&= \int_0^1 zeromeanf(variablex)^2zeromeang(variablex)^2\,dvariablex \\
&-2meanval(functionf)meanval(functiong)\int_0^1 zeromeanf(variablex)zeromeang(variablex)\,dvariablex +(\int_0^1 zeromeanf(variablex)zeromeang(variablex)\,dvariablex)^2 \\
&\geq -2meanval(functionf)meanval(functiong)\int_0^1 zeromeanf(variablex)zeromeang(variablex)\,dvariablex.
\end{align*}
Because of \eqref{eq:1}, it thus suffices to show that
\begin{equation}
2meanval(functionf)meanval(functiong)\int_0^1 zeromeanf(variablex)zeromeang(variablex)\,dvariablex
\label{eq:3} \leq \Var(functionf)\,maxbound(functiong)^2+\Var(functiong)\,maxbound(functionf)^2.
\end{equation}
Now since $(meanval(functiong) \; zeromeanf(variablex)-meanval(functionf) \; zeromeang(variablex))^2 \geq 0$ for all $variablex$, we have
\begin{align*}
2meanval(functionf)meanval(functiong) \int_0^1 zeromeanf(variablex)zeromeang(variablex)\,dvariablex
& \leq \int_0^1 (meanval(functiong)^2 zeromeanf(variablex)^2 + meanval(functionf)^2 zeromeang(variablex)^2) \, dvariablex \\
& = \Var(functionf) \, meanval(functiong)^2 + \Var(functiong) \, meanval(functionf)^2 \\
& \leq \Var(functionf) \, maxbound(functiong)^2 + \Var(functiong) \, maxbound(functionf)^2,
\end{align*}
establishing \eqref{eq:3} and completing the proof.

descriptive_long_confusing.solution:
\newcommand{\Var}{\mathrm{Var}}

Write $sheepdog(lanternfish)=hummingbird(lanternfish)-sunflower(hummingbird)$ and $paintbrush(lanternfish)=raincloud(lanternfish)-sunflower(raincloud)$, so that $\int_0^1 sheepdog(lanternfish)^2\,d lanternfish = \Var(hummingbird)$, $\int_0^1 paintbrush(lanternfish)^2\,d lanternfish = \Var(raincloud)$, and $\int_0^1 sheepdog(lanternfish)\,d lanternfish = \int_0^1 paintbrush(lanternfish)\,d lanternfish = 0$.  Now since $|raincloud(lanternfish)| \leq waterfall(raincloud)$ for all $lanternfish$, we have
$0 \leq \int_0^1 sheepdog(lanternfish)^2(\,waterfall(raincloud)^2-raincloud(lanternfish)^2)\,d lanternfish = \Var(hummingbird)\,waterfall(raincloud)^2-\int_0^1 sheepdog(lanternfish)^2 raincloud(lanternfish)^2\,d lanternfish$, and similarly $0 \leq \Var(raincloud)\,waterfall(hummingbird)^2-\int_0^1 hummingbird(lanternfish)^2 paintbrush(lanternfish)^2\,d lanternfish$.  Summing gives
\begin{equation}
\Var(hummingbird)\,waterfall(raincloud)^2+\Var(raincloud)\,waterfall(hummingbird)^2\label{eq:1}
\geq \int_0^1 \bigl(sheepdog(lanternfish)^2 raincloud(lanternfish)^2+hummingbird(lanternfish)^2 paintbrush(lanternfish)^2\bigr)\,d lanternfish.
\end{equation}

Now
\begin{align*}
&\int_0^1 \bigl(sheepdog(lanternfish)^2 raincloud(lanternfish)^2+hummingbird(lanternfish)^2 paintbrush(lanternfish)^2\bigr)\,d lanternfish-\Var(hummingbird\,raincloud)\\
&=\int_0^1 \Bigl(sheepdog(lanternfish)^2 raincloud(lanternfish)^2+hummingbird(lanternfish)^2 paintbrush(lanternfish)^2-\bigl(hummingbird(lanternfish) raincloud(lanternfish)-\int_0^1 hummingbird(driftwood) raincloud(driftwood)\,d driftwood\bigr)^2\Bigr)\,d lanternfish;
\end{align*}
substituting $sheepdog(lanternfish)+sunflower(hummingbird)$ for $hummingbird(lanternfish)$ and $paintbrush(lanternfish)+sunflower(raincloud)$ for $raincloud(lanternfish)$, and using $\int_0^1 sheepdog(lanternfish)\,d lanternfish = \int_0^1 paintbrush(lanternfish)\,d lanternfish = 0$, we obtain
\begin{align*}
&\int_0^1 \bigl(sheepdog(lanternfish)^2 raincloud(lanternfish)^2+hummingbird(lanternfish)^2 paintbrush(lanternfish)^2\bigr)\,d lanternfish-\Var(hummingbird\,raincloud)\\
&= \int_0^1 sheepdog(lanternfish)^2 paintbrush(lanternfish)^2\,d lanternfish \\
&\quad -2\,sunflower(hummingbird)\,sunflower(raincloud)\int_0^1 sheepdog(lanternfish) paintbrush(lanternfish)\,d lanternfish +\Bigl(\int_0^1 sheepdog(lanternfish) paintbrush(lanternfish)\,d lanternfish\Bigr)^2 \\
&\ge -2\,sunflower(hummingbird)\,sunflower(raincloud)\int_0^1 sheepdog(lanternfish) paintbrush(lanternfish)\,d lanternfish.
\end{align*}
Because of \eqref{eq:1}, it suffices to show that
\begin{equation}
2\,sunflower(hummingbird)\,sunflower(raincloud)\int_0^1 sheepdog(lanternfish) paintbrush(lanternfish)\,d lanternfish\label{eq:3}
\le \Var(hummingbird)\,waterfall(raincloud)^2+\Var(raincloud)\,waterfall(hummingbird)^2.
\end{equation}
Now, since $(sunflower(raincloud)\,sheepdog(lanternfish)-sunflower(hummingbird)\,paintbrush(lanternfish))^2 \ge 0$ for all $lanternfish$, we have
\begin{align*}
2\,sunflower(hummingbird)\,sunflower(raincloud) \int_0^1 sheepdog(lanternfish) paintbrush(lanternfish)\,d lanternfish
&\le \int_0^1 \bigl(sunflower(raincloud)^2 sheepdog(lanternfish)^2 + sunflower(hummingbird)^2 paintbrush(lanternfish)^2\bigr)\,d lanternfish\\
&= \Var(hummingbird)\,sunflower(raincloud)^2 + \Var(raincloud)\,sunflower(hummingbird)^2\\
&\le \Var(hummingbird)\,waterfall(raincloud)^2 + \Var(raincloud)\,waterfall(hummingbird)^2,
\end{align*}
which establishes \eqref{eq:3} and completes the proof.

descriptive_long_misleading.solution:
\newcommand{\Var}{\mathrm{Var}}

Write $unbalanced(constant) = discontinuous(constant)-extremum(discontinuous)$ and $lopsided(constant) = discrete(constant)-extremum(discrete)$, so that $\int_0^1 unbalanced(constant)^2\,dconstant = \Var(discontinuous)$, $\int_0^1 lopsided(constant)^2\,dconstant = \Var(discrete)$, and $\int_0^1 unbalanced(constant)\,dconstant = \int_0^1 lopsided(constant)\,dconstant = 0$. Now since $|discrete(constant)| \leq minvalue(discrete)$ for all $constant$, $0\leq \int_0^1 unbalanced(constant)^2(minvalue(discrete)^2-discrete(constant)^2)\,dconstant = \Var(discontinuous) minvalue(discrete)^2-\int_0^1 unbalanced(constant)^2discrete(constant)^2\,dconstant$, and similarly $0 \leq \Var(discrete)minvalue(discontinuous)^2-\int_0^1 discontinuous(constant)^2lopsided(constant)^2\,dconstant$. Summing gives
\begin{equation}
\Var(discontinuous)minvalue(discrete)^2+\Var(discrete)minvalue(discontinuous)^2
\label{eq:1}
\geq \int_0^1 (unbalanced(constant)^2discrete(constant)^2+discontinuous(constant)^2lopsided(constant)^2)\,dconstant.
\end{equation}
Now
\begin{align*}
&\int_0^1 (unbalanced(constant)^2discrete(constant)^2+discontinuous(constant)^2lopsided(constant)^2)\,dconstant-\Var(discontinuousdiscrete) \\&= \int_0^1 (unbalanced(constant)^2discrete(constant)^2+discontinuous(constant)^2lopsided(constant)^2-(discontinuous(constant)discrete(constant)-\int_0^1 discontinuous(staticval)discrete(staticval)\,dstaticval)^2)\,dconstant;
\end{align*}
substituting $unbalanced(constant)+extremum(discontinuous)$ for $discontinuous(constant)$ everywhere and $lopsided(constant)+extremum(discrete)$ for $discrete(constant)$ everywhere, and using the fact that $\int_0^1 unbalanced(constant)\,dconstant = \int_0^1 lopsided(constant)\,dconstant = 0$, we can expand and simplify the right hand side of this equation to obtain
\begin{align*}
&\int_0^1 (unbalanced(constant)^2discrete(constant)^2+discontinuous(constant)^2lopsided(constant)^2)\,dconstant-\Var(discontinuousdiscrete) \\
&= \int_0^1 unbalanced(constant)^2lopsided(constant)^2\,dconstant \\
&-2extremum(discontinuous)extremum(discrete)\int_0^1 unbalanced(constant)lopsided(constant)\,dconstant +(\int_0^1 unbalanced(constant)lopsided(constant)\,dconstant)^2 \\
&\geq -2extremum(discontinuous)extremum(discrete)\int_0^1 unbalanced(constant)lopsided(constant)\,dconstant.
\end{align*}
Because of \eqref{eq:1}, it thus suffices to show that
\begin{equation}
2extremum(discontinuous)extremum(discrete)\int_0^1 unbalanced(constant)lopsided(constant)\,dconstant
\label{eq:3} \leq \Var(discontinuous)minvalue(discrete)^2+\Var(discrete)minvalue(discontinuous)^2.
\end{equation}
Now since $(extremum(discrete) unbalanced(constant)-extremum(discontinuous) lopsided(constant))^2 \geq 0$ for all $constant$, we have
\begin{align*}
2extremum(discontinuous)extremum(discrete) \int_0^1 unbalanced(constant)lopsided(constant)\,dconstant
& \leq \int_0^1 (extremum(discrete)^2 unbalanced(constant)^2 + extremum(discontinuous)^2 lopsided(constant)^2) dconstant \\
& = \Var(discontinuous) extremum(discrete)^2 + \Var(discrete) extremum(discontinuous)^2 \\
& \leq \Var(discontinuous) minvalue(discrete)^2 + \Var(discrete) minvalue(discontinuous)^2,
\end{align*}
establishing \eqref{eq:3} and completing the proof.

