\newcommand{\Var}{\mathrm{Var}}

Write $kplmztwo(tslqjmrx) = qzxwvtnp(tslqjmrx)-hjgrksla(qzxwvtnp)$ and $rdbfycuv(tslqjmrx) = nvbshqel(tslqjmrx)-hjgrksla(nvbshqel)$, so that $\int_0^1 kplmztwo(tslqjmrx)^2\,d tslqjmrx = \Var(qzxwvtnp)$, $\int_0^1 rdbfycuv(tslqjmrx)^2\,d tslqjmrx = \Var(nvbshqel)$, and $\int_0^1 kplmztwo(tslqjmrx)\,d tslqjmrx = \int_0^1 rdbfycuv(tslqjmrx)\,d tslqjmrx = 0$. Now since $|nvbshqel(tslqjmrx)| \leq pbkrawmz(nvbshqel)$ for all $tslqjmrx$, $0\leq \int_0^1 kplmztwo(tslqjmrx)^2(pbkrawmz(nvbshqel)^2-nvbshqel(tslqjmrx)^2)\,d tslqjmrx = \Var(qzxwvtnp) pbkrawmz(nvbshqel)^2-\int_0^1 kplmztwo(tslqjmrx)^2 nvbshqel(tslqjmrx)^2\,d tslqjmrx$, and similarly $0 \leq \Var(nvbshqel) pbkrawmz(qzxwvtnp)^2-\int_0^1 qzxwvtnp(tslqjmrx)^2 rdbfycuv(tslqjmrx)^2\,d tslqjmrx$. Summing gives
\begin{equation}
\Var(qzxwvtnp) pbkrawmz(nvbshqel)^2+\Var(nvbshqel) pbkrawmz(qzxwvtnp)^2
\label{eq:1}
\geq \int_0^1 (kplmztwo(tslqjmrx)^2 nvbshqel(tslqjmrx)^2+qzxwvtnp(tslqjmrx)^2 rdbfycuv(tslqjmrx)^2)\,d tslqjmrx.
\end{equation}
Now
\begin{align*}
&\int_0^1 (kplmztwo(tslqjmrx)^2 nvbshqel(tslqjmrx)^2+qzxwvtnp(tslqjmrx)^2 rdbfycuv(tslqjmrx)^2)\,d tslqjmrx-\Var(qzxwvtnp nvbshqel) \\&= \int_0^1 (kplmztwo(tslqjmrx)^2 nvbshqel(tslqjmrx)^2+qzxwvtnp(tslqjmrx)^2 rdbfycuv(tslqjmrx)^2-(qzxwvtnp(tslqjmrx) nvbshqel(tslqjmrx)-\int_0^1 qzxwvtnp(wzndecot) nvbshqel(wzndecot)\,d wzndecot)^2)\,d tslqjmrx;
\end{align*}
substituting $kplmztwo(tslqjmrx)+hjgrksla(qzxwvtnp)$ for $qzxwvtnp(tslqjmrx)$ everywhere and $rdbfycuv(tslqjmrx)+hjgrksla(nvbshqel)$ for $nvbshqel(tslqjmrx)$ everywhere, and using the fact that $\int_0^1 kplmztwo(tslqjmrx)\,d tslqjmrx = \int_0^1 rdbfycuv(tslqjmrx)\,d tslqjmrx = 0$, we can expand and simplify the right hand side of this equation to obtain
\begin{align*}
&\int_0^1 (kplmztwo(tslqjmrx)^2 nvbshqel(tslqjmrx)^2+qzxwvtnp(tslqjmrx)^2 rdbfycuv(tslqjmrx)^2)\,d tslqjmrx-\Var(qzxwvtnp nvbshqel) \\
&= \int_0^1 kplmztwo(tslqjmrx)^2 rdbfycuv(tslqjmrx)^2\,d tslqjmrx \\
&-2 hjgrksla(qzxwvtnp) hjgrksla(nvbshqel)\int_0^1 kplmztwo(tslqjmrx) rdbfycuv(tslqjmrx)\,d tslqjmrx +\left(\int_0^1 kplmztwo(tslqjmrx) rdbfycuv(tslqjmrx)\,d tslqjmrx\right)^2 \\
&\geq -2 hjgrksla(qzxwvtnp) hjgrksla(nvbshqel)\int_0^1 kplmztwo(tslqjmrx) rdbfycuv(tslqjmrx)\,d tslqjmrx.
\end{align*}
Because of \eqref{eq:1}, it thus suffices to show that
\begin{equation}
2 hjgrksla(qzxwvtnp) hjgrksla(nvbshqel)\int_0^1 kplmztwo(tslqjmrx) rdbfycuv(tslqjmrx)\,d tslqjmrx
\label{eq:3} \leq \Var(qzxwvtnp) pbkrawmz(nvbshqel)^2+\Var(nvbshqel) pbkrawmz(qzxwvtnp)^2.
\end{equation}
Now since $(hjgrksla(nvbshqel) kplmztwo(tslqjmrx)-hjgrksla(qzxwvtnp) rdbfycuv(tslqjmrx))^2 \geq 0$ for all $tslqjmrx$, we have
\begin{align*}
2 hjgrksla(qzxwvtnp) hjgrksla(nvbshqel) \int_0^1 kplmztwo(tslqjmrx) rdbfycuv(tslqjmrx)\,d tslqjmrx
& \leq \int_0^1 (hjgrksla(nvbshqel)^2 kplmztwo(tslqjmrx)^2 + hjgrksla(qzxwvtnp)^2 rdbfycuv(tslqjmrx)^2) d tslqjmrx \\
& = \Var(qzxwvtnp) hjgrksla(nvbshqel)^2 + \Var(nvbshqel) hjgrksla(qzxwvtnp)^2 \\
& \leq \Var(qzxwvtnp) pbkrawmz(nvbshqel)^2 + \Var(nvbshqel) pbkrawmz(qzxwvtnp)^2,
\end{align*}
establishing \eqref{eq:3} and completing the proof.
